884	async function assertRequestFulfillmentReady(featureId, runDir, run) {
885	  const jsonPath = join(runDir, 'context', `request_fulfillment_${featureId}.json`);
886	  if (!(await fileExists(jsonPath))) {
887	    throw new Error(`Missing request fulfillment artifact: ${jsonPath}`);
888	  }
889	  const document = JSON.parse(await readFile(jsonPath, 'utf8'));
890	  const requirements = Array.isArray(document.requirements) ? document.requirements : [];
891	  for (const requirement of requirements) {
892	    if (String(requirement.status || '').trim().toLowerCase() !== 'satisfied') continue;
893	    const artifacts = Array.isArray(requirement.evidence_artifacts)
894	      ? requirement.evidence_artifacts
895	      : Array.isArray(requirement.required_artifacts)
896	        ? requirement.required_artifacts
897	        : [];
898	    for (const artifactPath of artifacts) {
899	      const absPath = join(runDir, String(artifactPath || '').trim());
900	      if (artifactPath && !(await fileExists(absPath))) {
901	        throw new Error(
902	          `Required artifact no longer exists (deleted or moved): ${artifactPath}. ` +
903	          `Cannot finalize without evidence for requirement ${requirement.requirement_id || 'unknown'}.`
904	        );
905	      }
906	    }
907	  }
908	  const unsatisfiedBlockingRequirements = collectUnsatisfiedBlockingRequirements(document);
909	  if (unsatisfiedBlockingRequirements.length > 0) {
910	    throw new Error(`Cannot finalize with unsatisfied blocking request requirements: ${unsatisfiedBlockingRequirements.join(', ')}`);
911	  }
912	  const validation = validateRequestFulfillmentStatus(document);
913	  if (!validation.ok) {
914	    throw new Error(validation.failures.join('; '));
915	  }
